define([],function(){"use strict";return{init:function(fromBox,toBox,correct,learned,nextUrl,feedbackstyle,delay){if(!delay){delay=1000;}var pills=document.querySelectorAll("[data-box]");pills.forEach(function(pill){var boxNum=parseInt(pill.getAttribute("data-box"),10);if(!boxNum){return;}if(boxNum===toBox&&toBox!==fromBox){pill.classList.add("lf-anim-pulse-in");if(correct){pill.style.boxShadow="0 0 12px rgba(102, 153, 51, 0.6)";}else{pill.style.boxShadow="0 0 12px rgba(249, 128, 18, 0.6)";}}});if(feedbackstyle===4){var pointsEl=document.querySelector(".lf-points-float");if(pointsEl){pointsEl.classList.add("lf-points-animate");}}if(nextUrl){setTimeout(function(){window.location.href=nextUrl;},delay);}}}});
